    private val JSON_MEDIA_TYPE = "application/json; charset=utf-8".toMediaType()

    // Secure client for cloud API (HTTPS)
    private val secureClient: OkHttpClient = OkHttpClient.Builder()
        .connectTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
        .readTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
        .writeTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
        .addInterceptor(LoggingInterceptor())
        .addInterceptor(AuthInterceptor())
        .retryOnConnectionFailure(true)
        .build()

    // Insecure client for local IoT devices (HTTP or self-signed HTTPS)
    private val localClient: OkHttpClient by lazy {
        createLocalClient()
    }

    private fun createLocalClient(): OkHttpClient {
        val trustAllCerts = arrayOf<TrustManager>(object : X509TrustManager {
            override fun checkClientTrusted(chain: Array<out X509Certificate>?, authType: String?) {}
            override fun checkServerTrusted(chain: Array<out X509Certificate>?, authType: String?) {}
            override fun getAcceptedIssuers(): Array<X509Certificate> = arrayOf()
        })

        val sslContext = SSLContext.getInstance("TLS")
        sslContext.init(null, trustAllCerts, SecureRandom())
        val sslSocketFactory = sslContext.socketFactory

        return OkHttpClient.Builder()
            .connectTimeout(LOCAL_DEVICE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .readTimeout(LOCAL_DEVICE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .writeTimeout(LOCAL_DEVICE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .sslSocketFactory(sslSocketFactory, trustAllCerts[0] as X509TrustManager)
            .hostnameVerifier { _, _ -> true }
            .addInterceptor(LoggingInterceptor())
            .retryOnConnectionFailure(true)
            .build()
    }

    private fun getClientForUrl(url: String): OkHttpClient {
        return if (isLocalNetwork(url)) localClient else secureClient
    }

    private fun isLocalNetwork(url: String): Boolean {
        return url.contains(LOCAL_NETWORK_PREFIX) ||
                url.contains("10.0.") ||
                url.contains("172.16.") ||
                url.startsWith("http://")
    }

    // --- Cloud API Methods ---

    fun cloudGet(
        endpoint: String,
        headers: Map<String, String>? = null,
        callback: IoTResponseCallback
    ) {
        val url = "$CLOUD_BASE_URL$endpoint"
        get(url, headers, callback)
    }

    fun cloudPost(
        endpoint: String,
