        path: String = "/",
        useHttps: Boolean = false,
        headers: Map<String, String>? = null,
        callback: IoTResponseCallback
    ) {
        val protocol = if (useHttps) "https" else "http"
        val url = "$protocol://$deviceIp:$port$path"
        get(url, headers, callback)
    }

    fun devicePost(
        deviceIp: String,
        port: Int = 80,
        path: String = "/",
        jsonBody: JSONObject,
        useHttps: Boolean = false,
