        callback: IoTResponseCallback
    ) {
        val protocol = if (useHttps) "https" else "http"
        val url = "$protocol://$deviceIp:$port$path"
        post(url, jsonBody, headers, callback)
    }

    fun devicePut(
        deviceIp: String,
        port: Int = 80,
        path: String = "/",
        jsonBody: JSONObject,
        useHttps: Boolean = false,
        headers: Map<String, String>? = null,
        callback: IoTResponseCallback
    ) {
        val protocol = if (useHttps) "https" else "http"
        val url = "$protocol://$deviceIp:$port$path"
        put(url, jsonBody, headers, callback)
    }

    // --- Send Command to Device ---

    fun sendCommand(
        deviceIp: String,
        port: Int = 80,
        command: String,
        params: Map<String, Any>? = null,
        useHttps: Boolean = false,
        callback: IoTResponseCallback
    ) {
        val json = JSONObject().apply {
            put("command", command)
            params?.forEach { (key, value) -> put(key, value) }
            put("timestamp", System.currentTimeMillis())
        }
        devicePost(deviceIp, port, "/api/command", json, useHttps, null, callback)
    }

    // --- Generic HTTP Methods ---

    fun get(
        url: String,
        headers: Map<String, String>? = null,
        callback: IoTResponseCallback
    ) {
        val requestBuilder = Request.Builder().url(url).get()
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(requestBuilder.build(), url, callback)
    }

    fun post(
        url: String,
        jsonBody: JSONObject,
        headers: Map<String, String>? = null,
        callback: IoTResponseCallback
    ) {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).post(body)
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(requestBuilder.build(), url, callback)
    }

    fun put(
        url: String,
        jsonBody: JSONObject,
        headers: Map<String, String>? = null,
        callback: IoTResponseCallback
    ) {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).put(body)
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(requestBuilder.build(), url, callback)
    }

    fun delete(
        url: String,
        headers: Map<String, String>? = null,
        callback: IoTResponseCallback
    ) {
        val requestBuilder = Request.Builder().url(url).delete()
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        executeRequest(requestBuilder.build(), url, callback)
    }

    // --- Synchronous Methods ---

    @Throws(IOException::class)
    fun getSync(url: String, headers: Map<String, String>? = null): IoTResponse {
        val requestBuilder = Request.Builder().url(url).get()
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        return executeRequestSync(requestBuilder.build(), url)
    }

    @Throws(IOException::class)
    fun postSync(
        url: String,
        jsonBody: JSONObject,
        headers: Map<String, String>? = null
    ): IoTResponse {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).post(body)
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        return executeRequestSync(requestBuilder.build(), url)
    }

    private fun executeRequest(request: Request, url: String, callback: IoTResponseCallback) {
        val client = getClientForUrl(url)

        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Request failed: ${request.url}", e)
                callback.onError(IoTError(
                    message = e.message ?: "Unknown error",
                    exception = e,
                    url = url,
                    isNetworkError = true
                ))
            }

            override fun onResponse(call: Call, response: Response) {
                response.use {
                    val responseBody = it.body?.string()
                    val iotResponse = IoTResponse(
                        statusCode = it.code,
                        body = responseBody,
                        headers = parseHeaders(it.headers),
                        url = url,
                        isSuccessful = it.isSuccessful
                    )

                    if (it.isSuccessful) {
                        callback.onSuccess(iotResponse)
                    } else {
                        callback.onError(IoTError(
                            message = "HTTP ${it.code}: ${it.message}",
                            url = url,
                            statusCode = it.code,
                            responseBody = responseBody,
                            isNetworkError = false
                        ))
                    }
                }
            }
        })
    }

    @Throws(IOException::class)
    private fun executeRequestSync(request: Request, url: String): IoTResponse {
        val client = getClientForUrl(url)
        val response = client.newCall(request).execute()

        return response.use {
            IoTResponse(
                statusCode = it.code,
                body = it.body?.string(),
                headers = parseHeaders(it.headers),
                url = url,
                isSuccessful = it.isSuccessful
            )
        }
    }

    private fun parseHeaders(headers: Headers): Map<String, String> {
        val map = mutableMapOf<String, String>()
        for (i in 0 until headers.size) {
            map[headers.name(i)] = headers.value(i)
        }
        return map
    }

    // --- Device Discovery ---

    fun discoverDevices(
        subnet: String = "192.168.1",
        port: Int = 80,
        path: String = "/api/info",
        callback: DeviceDiscoveryCallback
    ) {
        val discoveredDevices = mutableListOf<DiscoveredDevice>()
        var completedCount = 0
        val totalDevices = 254

        for (i in 1..254) {
            val ip = "$subnet.$i"
            val url = "http://$ip:$port$path"

            val fastClient = localClient.newBuilder()
                .connectTimeout(1, TimeUnit.SECONDS)
                .readTimeout(1, TimeUnit.SECONDS)
                .build()

            val request = Request.Builder().url(url).get().build()

            fastClient.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    synchronized(discoveredDevices) {
                        completedCount++
                        if (completedCount >= totalDevices) {
                            callback.onDiscoveryComplete(discoveredDevices.toList())
                        }
                    }
                }

                override fun onResponse(call: Call, response: Response) {
                    response.use {
                        synchronized(discoveredDevices) {
                            if (it.isSuccessful) {
                                val body = it.body?.string()
                                val device = DiscoveredDevice(
                                    ip = ip,
                                    port = port,
                                    info = body
                                )
                                discoveredDevices.add(device)
                                callback.onDeviceFound(device)
                            }
                            completedCount++
                            if (completedCount >= totalDevices) {
                                callback.onDiscoveryComplete(discoveredDevices.toList())
                            }
                        }
                    }
                }
            })
        }
    }

    fun shutdown() {
        secureClient.dispatcher.executorService.shutdown()
        localClient.dispatcher.executorService.shutdown()
        secureClient.connectionPool.evictAll()
        localClient.connectionPool.evictAll()
    }

    // --- Interceptors ---

    private class LoggingInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val request = chain.request()
            val startTime = System.nanoTime()

            Log.d(TAG, "--> ${request.method} ${request.url}")

            val response = chain.proceed(request)
            val duration = (System.nanoTime() - startTime) / 1_000_000

            Log.d(TAG, "<-- ${response.code} ${request.url} (${duration}ms)")

            return response
        }
    }

    private class AuthInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val originalRequest = chain.request()

            // Only add auth header for cloud API requests
            if (originalRequest.url.host == "api.example.com") {
                val token = getAuthToken()
                if (token != null) {
                    val authenticatedRequest = originalRequest.newBuilder()
                        .addHeader("Authorization", "Bearer $token")
                        .build()
                    return chain.proceed(authenticatedRequest)
                }
            }

            return chain.proceed(originalRequest)
        }

        private fun getAuthToken(): String? {
            // Replace with actual token retrieval logic
            return null
        }
    }
