// --- Data Classes ---

data class IoTResponse(
    val statusCode: Int,
    val body: String?,
    val headers: Map<String, String>,
    val url: String,
    val isSuccessful: Boolean
) {
    fun bodyAsJson(): JSONObject? {
        return try {
            body?.let { JSONObject(it) }
        } catch (e: Exception) {
            null
        }
    }
}

data class IoTError(
    val message: String,
    val exception: Exception? = null,
    val url: String,
    val statusCode: Int? = null,
    val responseBody: String? = null,
    val isNetworkError: Boolean
)

data class DiscoveredDevice(
    val ip: String,
    val port: Int,
    val info: String?
)

// --- Callbacks ---

interface IoTResponseCallback {
    fun onSuccess(response: IoTResponse)
    fun onError(error: IoTError)
}

interface DeviceDiscoveryCallback {
    fun onDeviceFound(device: DiscoveredDevice)
    fun onDiscoveryComplete(devices: List<DiscoveredDevice>)
}

// --- Example Activity Usage ---

class MainActivity : AppCompatActivity() {

    private val iotClient = IoTHttpClient.getInstance()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Example: Get device status from local IoT device (HTTP)
        fetchDeviceStatus("192.168.1.100")

        // Example: Send command to local IoT device
        sendDeviceCommand("192.168.1.100", "toggle_light", mapOf("brightness" to 75))

        // Example: Fetch data from cloud API (HTTPS)
        fetchCloudDevices()

        // Example: Register device with cloud
        registerDeviceWithCloud("192.168.1.100", "Smart Light")

        // Example: Discover devices on local network
        discoverLocalDevices()
    }

    private fun fetchDeviceStatus(deviceIp: String) {
        iotClient.deviceGet(
            deviceIp = deviceIp,
            port = 80,
            path = "/api/status",
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    val json = response.bodyAsJson()
                    runOnUiThread {
                        Log.d("MainActivity", "Device status: $json")
                    }
                }

                override fun onError(error: IoTError) {
                    runOnUiThread {
                        Log.e("MainActivity", "Failed to get device status: ${error.message}")
                    }
                }
            }
        )
    }

    private fun sendDeviceCommand(deviceIp: String, command: String, params: Map<String, Any>) {
        iotClient.sendCommand(
            deviceIp = deviceIp,
            port = 80,
            command = command,
            params = params,
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    runOnUiThread {
                        Log.d("MainActivity", "Command sent successfully: ${response.body}")
                    }
                }

                override fun onError(error: IoTError) {
                    runOnUiThread {
                        Log.e("MainActivity", "Failed to send command: ${error.message}")
                    }
                }
            }
        )
    }

    private fun fetchCloudDevices() {
        iotClient.cloudGet(
            endpoint = "/v1/devices",
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    runOnUiThread {
                        Log.d("MainActivity", "Cloud devices: ${response.body}")
                    }
                }

                override fun onError(error: IoTError) {
                    runOnUiThread {
                        Log.e("MainActivity", "Failed to fetch cloud devices: ${error.message}")
                    }
                }
            }
        )
    }

    private fun registerDeviceWithCloud(deviceIp: String, deviceName: String) {
        val body = JSONObject().apply {
            put("name", deviceName)
            put("local_ip", deviceIp)
            put("type", "smart_light")
        }

        iotClient.cloudPost(
            endpoint = "/v1/devices/register",
            jsonBody = body,
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    runOnUiThread {
                        Log.d("MainActivity", "Device registered: ${response.body}")
                    }
                }

                override fun onError(error: IoTError) {
                    runOnUiThread {
                        Log.e("MainActivity", "Failed to register device: ${error.message}")
                    }
                }
            }
        )
    }

    private fun discoverLocalDevices() {
        iotClient.discoverDevices(
            subnet = "192.168.1",
            port = 80,
            path = "/api/info",
            callback = object : DeviceDiscoveryCallback {
                override fun onDeviceFound(device: DiscoveredDevice) {
                    runOnUiThread {
                        Log.d("MainActivity", "Found device: ${device.ip} - ${device.info}")
                    }
                }

                override fun onDiscoveryComplete(devices: List<DiscoveredDevice>) {
                    runOnUiThread {
                        Log.d("MainActivity", "Discovery complete. Found ${devices.size} devices.")
                    }
                }
            }
        )
    }

    override fun onDestroy() {
        super.onDestroy()
        iotClient.shutdown()
    }
}